body:
It's incorrect to sink an expression if its subexpression is mutated by blocking assignments (or other side-effecting operations). This PR fixes the bug by checking the users of inout operations and preventing Prettify from sinking expressions. Since it's necessary to traverse the IR to analysis users, it might be costly without cache so I introduced a class `SideEffectTracker` to first store unsafe declarations and to provide APIs to answer immutability of expressions. 

Fix https://github.com/llvm/circt/issues/4532 (though we still have a similar issue in Prepare spills expressions without considering blocking assignments). The output verilog is:
```
module Main(
  input  [1:0] IA,
               IB,
  input        IS,
  output [1:0] O);

  reg        _GEN;
  reg        _GEN_0;
  reg        _GEN_1;
  reg        _GEN_2;
  wire [2:0] _GEN_3 = {{2{_GEN_0}}, _GEN} + {{2{_GEN_2}}, _GEN_1};
  reg        _GEN_4;
  reg        _GEN_5;
  always_comb begin
    if (IS) begin
      _GEN = 1'h0;
      _GEN_0 = 1'h0;
      _GEN_1 = IB[0];
      _GEN_2 = IB[1];
    end
    else begin
      _GEN = IA[0];
      _GEN_0 = IA[1];
      _GEN_1 = 1'h1;
      _GEN_2 = 1'h0;
    end
    if (_GEN_3[2:1] == 2'h1) begin
      _GEN_4 = 1'h1;
      _GEN_5 = 1'h0;
    end
    else if (_GEN_3[2:1] == 2'h2) begin
      _GEN_4 = 1'h0;
      _GEN_5 = 1'h1;
    end
    else begin
      _GEN_4 = _GEN_3[0];
      _GEN_5 = _GEN_3[1];
    end
  end // always_comb
  assign O = {_GEN_5, _GEN_4};
endmodule
```
